using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed the default discriminator from "Discriminator" to "$type".
            // Existing 500K documents use "Discriminator"; preserve it so they remain queryable
            // and so direct SQL queries (c.Discriminator) continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "EntityType|Key" to just "Key".
            // Existing documents have ids like "Product|123"; preserve this format
            // so FindAsync and point-reads still resolve against existing data.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // REMOVED: HasIndex() — EF Core 9 Cosmos provider now throws at startup
        // instead of silently ignoring it. Cosmos DB indexing is managed via
        // the container's indexing policy (Azure Portal / Bicep / Terraform).
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

