using System.Linq;

class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O.
    // ToList(), SaveChanges(), etc. now throw — use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we configured
        // HasDiscriminator<string>("Discriminator") in OnModelCreating.
        // If we hadn't, EF Core 9 would write "$type" instead, breaking this query.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        var products = await ctx.Products
            .Where(p => p.Sku == "ABC")
            .ToListAsync();
    }
}

